transcript.text:
{
  "체계": "분류(산업/기술/기타), 영향도(1~10점: 에너지 시장 파급력 및 자본 효율성), 실현가능성(1~10점: 기술 성숙도 및 현장 적용 가능성)",
  "기사": [
    {
      "no": 1,
      "label": "산업",
      "score": 6,
      "reason": "흑자 전환했으나 보조금 의존도가 높아 전기차 시장 변동에 따른 불확실성이 큽니다."
    },
    {
      "no": 2,
      "label": "산업",
      "score": 5,
      "reason": "바이오연료 시장 확장을 통한 매출 구조 개선 시도이나 단기 파급력은 제한적입니다."
    },
    {
      "no": 3,
      "label": "기술",
      "score": 8,
      "reason": "전력망 한계를 AI와 ESS 통합 관리로 해결하는 기술은 시장의 시급한 요구사항입니다."
    },
    {
      "no": 4,
      "label": "기술",
      "score": 6,
      "reason": "제조 공정 내 AI 도입은 생산성 향상에 기여하지만 보편적인 공정 혁신 수준입니다."
    },
    {
      "no": 5,
      "label": "기타",
      "score": 2,
      "reason": "공공기관의 사회공헌 활동으로 전력 산업 시장 환경에 미치는 실질적 영향이 적습니다."
    },
    {
      "no": 6,
      "label": "산업",
      "score": 7,
      "reason": "원전의 수익 모델을 의료·산업용으로 다각화하는 원전 생태계 확장 전략입니다."
    },
    {
      "no": 7,
      "label": "기타",
      "score": 1,
      "reason": "통신사의 보안 서비스 강화 기사로 에너지 부문 연관성이 없습니다."
    },
    {
      "no": 8,
      "label": "기술",
      "score": 9,
      "reason": "지능형 전력망과 도시 인프라를 통합하는 데이터 처리 모델로서 미래 인프라 표준을 제시합니다."
    }
  ],
  "주목": "[3], [8]은 분산 에너지와 지능형 전력망의 결합이라는 핵심 기술 흐름을 보여주며 전력 시장의 구조적 변화를 견인할 것으로 예상됩니다."
}
